module.exports = function(options) {
  var bases, corepath;
  corepath = require('path');
  return bases = {
    global: function() {
      return [];
    },
    system: function() {
      return [process.env.ALLUSERSPROFILE];
    },
    user: function() {
      return [process.env.APPDATA, process.env.USERPROFILE + '\\.conf\\', process.env.USERPROFILE + '\\conf\\'];
    },
    local: function() {
      var array, path;
      array = [];
      path = process.cwd();
      array.push(path + corepath.sep);
      while (path !== corepath.sep) {
        path = corepath.dirname(path);
        if (path.length !== 1) {
          path += corepath.sep;
        }
        array.unshift(path);
      }
      return array;
    }
  };
};
